use autoeq::roomeq::{ChannelOptimizationResult, RoomConfig, RoomOptimizationResult};

pub(super) fn is_bass_managed_coverage_scenario(scenario: &str) -> bool {
    // These scenarios route bass through dedicated sub/LFE paths. The
    // low-latency workflow is the stable coverage contract for that path; FIR
    // and hybrid phase modes are exercised by targeted QA instead.
    scenario.contains("_2_1")
        || scenario.contains("_5_1")
        || scenario.contains("multi_sub")
        || scenario.contains("multi_seat_2_1")
        || scenario.contains("2_2_mso")
        || scenario.contains("2_2_cardioid")
}

pub(super) fn is_subwoofer_channel(config: &RoomConfig, channel_name: &str) -> bool {
    if let Some(system) = &config.system
        && let Some(subwoofers) = &system.subwoofers
    {
        if channel_name.eq_ignore_ascii_case("lfe") {
            return true;
        }
        if let Some(measurement_key) = system.speakers.get(channel_name) {
            return subwoofers.mapping.contains_key(measurement_key);
        }
    }

    let lower = channel_name.to_lowercase();
    lower == "lfe" || lower == "sub" || lower.starts_with("sub")
}

pub(super) fn qa_primary_score_pair(
    result: &RoomOptimizationResult,
    config: &RoomConfig,
) -> (f64, f64) {
    let main_channels: Vec<&ChannelOptimizationResult> = result
        .channel_results
        .iter()
        .filter(|(name, _)| !is_subwoofer_channel(config, name))
        .map(|(_, ch)| ch)
        .collect();
    let channels: Vec<&ChannelOptimizationResult> = if main_channels.len() > 1 {
        main_channels
    } else {
        result.channel_results.values().collect()
    };
    let count = channels.len().max(1) as f64;
    let pre = channels.iter().map(|ch| ch.pre_score).sum::<f64>() / count;
    let post = channels.iter().map(|ch| ch.post_score).sum::<f64>() / count;
    (pre, post)
}

pub(super) fn has_subwoofer_channel(result: &RoomOptimizationResult, config: &RoomConfig) -> bool {
    result
        .channel_results
        .keys()
        .any(|name| is_subwoofer_channel(config, name))
}
